      const rendererLabel = rendererLabels[rendererKey] || rendererKey;
      const badgeMarkup = ok ? `<a class="preview-output-badge preview-output-badge-link is-ready" href="${getPreviewOutputUrl(rendererKey)}" target="_blank" rel="noopener">${rendererLabel} Ready</a>` : `<span class="preview-output-badge is-failed">${rendererLabel} Failed</span>`;
